import { useState } from 'react';
import api from '../services/api';

const TaskForm = ({ onTaskCreated }) => {
  const [title, setTitle] = useState('');
  const [deadline, setDeadline] = useState('');
  const [assignedTo, setAssignedTo] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await api.post('/tasks', { 
        title, 
        deadline, 
        assignedTo, 
        project: 'General Project' 
      });
      
      setTitle('');
      setDeadline('');
      setAssignedTo('');
      
      if (onTaskCreated) onTaskCreated();
    } catch (err) {
      alert('Failed to create task. Please verify the User ID.');
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr auto', gap: '10px', alignItems: 'end' }}>
      <div>
        <label style={{ fontSize: '0.75rem', fontWeight: '600', color: '#64748b' }}>TASK TITLE</label>
        <input 
          type="text" 
          placeholder="e.g. Design System" 
          value={title} 
          onChange={(e) => setTitle(e.target.value)} 
          required 
          style={{ margin: '5px 0 0 0' }}
        />
      </div>
      <div>
        <label style={{ fontSize: '0.75rem', fontWeight: '600', color: '#64748b' }}>DEADLINE</label>
        <input 
          type="date" 
          value={deadline} 
          onChange={(e) => setDeadline(e.target.value)} 
          required 
          style={{ margin: '5px 0 0 0' }}
        />
      </div>
      <div>
        <label style={{ fontSize: '0.75rem', fontWeight: '600', color: '#64748b' }}>ASSIGN TO (ID)</label>
        <input 
          type="text" 
          placeholder="User ObjectId" 
          value={assignedTo} 
          onChange={(e) => setAssignedTo(e.target.value)} 
          required 
          style={{ margin: '5px 0 0 0' }}
        />
      </div>
      <button type="submit" style={{ height: '42px', padding: '0 20px' }}>
        Create Task
      </button>
    </form>
  );
};

export default TaskForm;
